function CameraScanner({onCode}:{onCode(code:string):void}){const video=useRef<HTMLVideoElement>(null);const[active,setActive]=useState(false);const[error,setError]=useState("");const stream=useRef<MediaStream|null>(null);useEffect(()=>()=>stream.current?.getTracks().forEach(track=>track.stop()),[]);async function start(){try{stream.current=await navigator.mediaDevices.getUserMedia({video:{facingMode:"environment"},audio:false});if(!video.current)return;video.current.srcObject=stream.current;await video.current.play();setActive(true);const Detector=(window as unknown as{BarcodeDetector?:new(options:{formats:string[]})=>{detect(video:HTMLVideoElement):Promise<Array<{rawValue:string}>>}}).BarcodeDetector;if(!Detector){setError("El navegador no ofrece detección nativa; usá el ingreso manual.");return;}const detector=new Detector({formats:["qr_code"]});const timer=window.setInterval(async()=>{if(!video.current)return;const codes=await detector.detect(video.current).catch(()=>[]);if(codes[0]?.rawValue){onCode(codes[0].rawValue);window.clearInterval(timer);stream.current?.getTracks().forEach(track=>track.stop());setActive(false);}},450);}catch{setError("No se pudo acceder a la cámara. Revisá el permiso o usá el código manual.");}}return <div className="aspect-[4/3] max-h-[380px] rounded-2xl bg-[#0b1220] text-white grid place-items-center text-center relative overflow-hidden"><video ref={video} playsInline muted className={`absolute inset-0 size-full object-cover ${active?"block":"hidden"}`}/><div className="absolute inset-8 border-2 border-white/40 rounded-3xl z-10 pointer-events-none"/><div className={`relative z-20 p-8 ${active?"hidden":"block"}`}><Camera size={46} className="mx-auto text-white/70"/><h3 className="font-black mt-4">Escáner de cámara</h3><p className="text-white/55 text-sm mt-2">La cámara se activa bajo permiso explícito.</p><button onClick={start} className="btn bg-white text-[#0b1220] mt-5">Activar cámara</button>{error&&<p className="text-xs text-amber-200 mt-3">{error}</p>}</div></div>}

function Dashboard({ instructor = false }: { instructor?: boolean }) {
  const { state } = useDemo();
  const students = state.students.filter((student) => student.workspaceId === workspaceId);
  const confirmed = state.payments.filter((payment) => payment.workspaceId === workspaceId && payment.status === "confirmed").reduce((sum, payment) => sum + payment.amountCents, 0);
  const debt = state.charges.filter((charge) => charge.workspaceId === workspaceId && ["pending", "partial", "overdue"].includes(charge.status)).reduce((sum, charge) => sum + charge.amountCents - charge.paidCents, 0);
  const estimate = commissionAmount(confirmed, 4000);
  const instructorName = "Tomás Herrera";
  const myPendingRequests = state.requests.filter((r) => r.workspaceId === workspaceId && r.requester === instructorName && r.status === "pending");
  const myLastSettlement = state.settlements.filter((s) => s.instructor === instructorName).slice().sort((a, b) => b.closedAt.localeCompare(a.closedAt))[0];
  if (instructor) return <>
    <PageHeader eyebrow="Portal docente" title="Buen día, Tomás" description="Tu próxima clase y el estado de tus comisiones oficiales." />
    <div className="grid sm:grid-cols-2 xl:grid-cols-4 gap-4"><Metric label="Próxima clase" value="Hoy · 18:00" note="Barbería Inicial A · Centro"/><Metric label="Alumnos oficiales" value="8" note="Nómina derivada de inscripciones" tone="blue"/><Metric label="Asistencia pendiente" value="1 clase" note="Ventana abierta hasta las 02:00" tone="gold"/><Metric label="Comisión estimada" value={formatMoney(estimate)} note="Sujeta a cierre y reversiones"/></div>
    <div className="grid xl:grid-cols-[1.35fr_.65fr] gap-5 mt-6"><section className="card p-5"><h3 className="font-black">Clase de hoy</h3><div className="mt-4 rounded-2xl bg-[var(--sidebar)] text-white p-6 flex flex-col sm:flex-row sm:items-center gap-5"><div className="grid place-items-center size-14 rounded-2xl bg-white/10"><Calendar/></div><div><p className="text-white/60 text-xs">18:00 — 20:00</p><h4 className="text-xl font-black mt-1">Barbería Inicial A</h4><p className="text-sm text-white/70 mt-1">Sede Centro · Aula Taller 1</p></div><Link href="/instructor/classes" className="btn bg-white text-[var(--sidebar)] sm:ml-auto">Tomar asistencia <ArrowRight size={16}/></Link></div></section><section className="card p-5"><h3 className="font-black">Avisos</h3><div className="mt-4 space-y-3">{myPendingRequests.length>0?myPendingRequests.map(r=><p key={r.id} className="rounded-xl bg-amber-50 p-3 text-sm"><strong>{r.type.replaceAll("_"," ")}</strong><br/><span className="muted">{r.reason}</span></p>):<p className="rounded-xl bg-emerald-50 p-3 text-sm"><strong>Sin solicitudes pendientes</strong><br/><span className="muted">No tenés correcciones esperando resolución.</span></p>}{myLastSettlement&&<p className="rounded-xl bg-emerald-50 p-3 text-sm"><strong>Liquidación de {myLastSettlement.periodLabel} cerrada</strong><br/><span className="muted">Comprobante disponible</span></p>}</div></section></div>
  </>;
  return <>
    <PageHeader eyebrow="Panel operativo" title="Resumen de Academia Fusión" description="Indicadores oficiales del workspace, actualizados con los movimientos registrados." action={<button className="btn btn-secondary"><Download size={17}/> Exportar resumen</button>}/>
    <div className="grid grid-cols-2 xl:grid-cols-4 gap-3 sm:gap-4"><Metric label="Alumnos activos" value={String(students.filter((item) => item.status === "active").length)} note="+4 altas este mes"/><Metric label="Cobrado en julio" value={formatMoney(confirmed)} note="Solo pagos confirmados"/><Metric label="Deuda vigente" value={formatMoney(debt)} note="9 cargos requieren atención" tone="gold"/><Metric label="Liquidación estimada" value={formatMoney(estimate)} note="40% sobre base elegible" tone="blue"/></div>
    <div className="grid xl:grid-cols-[1.45fr_.55fr] gap-5 mt-6"><section className="card p-5 sm:p-6"><div className="flex justify-between"><div><h3 className="font-black">Recaudación mensual</h3><p className="muted text-xs mt-1">Pagos confirmados · últimos 6 meses</p></div><span className="badge badge-success">+12,4%</span></div><div className="h-52 mt-7 flex items-end gap-3 sm:gap-6 border-b border-[var(--line)] px-2">{[43,55,48,72,65,86].map((value,index)=><div key={index} className="flex-1 flex flex-col justify-end gap-2 h-full"><div className="rounded-t-lg bg-[var(--brand)]/85 hover:bg-[var(--brand)] transition" style={{height:`${Math.round((value/100)*180)}px`}}/><span className="text-[10px] text-center muted">{["Feb","Mar","Abr","May","Jun","Jul"][index]}</span></div>)}</div></section><section className="card p-5 sm:p-6"><h3 className="font-black">Atención requerida</h3><div className="mt-5 space-y-4"><Link href="/app/requests" className="flex gap-3"><span className="grid place-items-center size-10 rounded-xl bg-amber-50 text-amber-700"><Clock3 size={18}/></span><span className="text-sm"><strong>2 solicitudes pendientes</strong><small className="block muted mt-1">Requieren resolución</small></span><ChevronRight className="ml-auto muted" size={18}/></Link><Link href="/app/payments" className="flex gap-3"><span className="grid place-items-center size-10 rounded-xl bg-sky-50 text-sky-700"><Banknote size={18}/></span><span className="text-sm"><strong>1 transferencia</strong><small className="block muted mt-1">Pendiente de validar</small></span><ChevronRight className="ml-auto muted" size={18}/></Link><Link href="/app/alerts" className="flex gap-3"><span className="grid place-items-center size-10 rounded-xl bg-red-50 text-red-700"><ShieldAlert size={18}/></span><span className="text-sm"><strong>1 alerta alta</strong><small className="block muted mt-1">Acceso sin inscripción</small></span><ChevronRight className="ml-auto muted" size={18}/></Link></div></section></div>
    <section className="card mt-6"><div className="p-5 border-b border-[var(--line)] flex justify-between"><div><h3 className="font-black">Clases de hoy</h3><p className="muted text-xs mt-1">2 clases en Sede Centro</p></div><Link href="/app/classes" className="text-sm font-bold text-[var(--brand)]">Ver calendario</Link></div><div className="table-wrap"><table><thead><tr><th>Horario</th><th>Comisión</th><th>Profesor</th><th>Ocupación</th><th>Estado</th></tr></thead><tbody>{state.classes.filter(c=>c.workspaceId===workspaceId).slice(0,2).map(c=>{const cohort=state.cohorts.find(item=>item.id===c.cohortId)!;return <tr key={c.id}><td><strong>{c.startsAt} — {c.endsAt}</strong></td><td>{cohort.name}<small className="block muted">{cohort.code}</small></td><td>{cohort.instructor}</td><td>{cohort.enrolled}/{cohort.capacity}</td><td><StatusBadge value={c.status}/></td></tr>})}</tbody></table></div></section>
  </>;
}

function ReceptionDashboard() { const {state}=useDemo();const todayPayments=state.payments.filter(p=>p.workspaceId===workspaceId&&new Date(p.registeredAt).toDateString()===new Date().toDateString()).reduce((s,p)=>s+(p.status==="confirmed"?p.amountCents:0),0);return <><PageHeader eyebrow="Recepción · Sede Centro" title="Operación de hoy" description="Clases, accesos, cobros y caja dentro de tu sede asignada." action={<Link href="/app/check-in" className="btn btn-primary"><QrCode size={18}/> Abrir escáner</Link>}/><div className="grid grid-cols-1 sm:grid-cols-3 gap-4"><Metric label="Clases del día" value="2" note="1 abierta · 1 finalizada"/><Metric label="Check-ins" value={String(state.checkins.filter(c=>c.workspaceId===workspaceId).length)} note="1 requiere atención" tone="blue"/><Metric label="Cobrado hoy" value={formatMoney(todayPayments)} note="Pagos confirmados"/></div><div className="grid md:grid-cols-3 gap-4 mt-6"><Link href="/app/students" className="card p-6"><GraduationCap className="text-[var(--brand)]"/><h3 className="font-black mt-4">Registrar alumno</h3><p className="muted text-sm mt-1">Alta operativa y tutor si es menor.</p></Link><Link href="/app/payments" className="card p-6"><CircleDollarSign className="text-[var(--brand)]"/><h3 className="font-black mt-4">Registrar pago</h3><p className="muted text-sm mt-1">Efectivo, transferencia o parcial.</p></Link><Link href="/app/cash" className="card p-6"><WalletCards className="text-[var(--brand)]"/><h3 className="font-black mt-4">Controlar caja</h3><p className="muted text-sm mt-1">Esperado, contado y diferencia.</p></Link></div></>}

function normalizeSearch(text:string){return text.toLowerCase().normalize("NFD").replace(/[̀-ͯ]/g,"")}
function teacherSlug(name:string){return normalizeSearch(name).replace(/[^a-z0-9]+/g,"-").replace(/(^-|-$)/g,"")}

const scheduleWeekdays=["Lunes","Martes","Miércoles","Jueves","Viernes","Sábado"];

function NewCohortModal({open,onClose,defaultInstructor,defaultCourseId}:{open:boolean;onClose():void;defaultInstructor?:string;defaultCourseId?:string}){
  const{state,addCohort,addClassesForCohort}=useDemo();
  const instructorNames=Array.from(new Set(state.cohorts.filter(c=>c.workspaceId===workspaceId).map(c=>c.instructor)));
  const[courseId,setCourseId]=useState(defaultCourseId??"");
  const[installments,setInstallments]=useState(()=>{const c=defaultCourseId?state.courses.find(x=>x.id===defaultCourseId):undefined;return c?String(Math.min(12,c.durationMonths)):""});
  const[weekdays,setWeekdays]=useState<string[]>([]);
  const[commissionPercent,setCommissionPercent]=useState("40");
  const course=state.courses.find(c=>c.id===courseId);
  const installmentsNum=Math.max(1,Math.round(Number(installments))||1);
  const perInstallment=course?Math.round(course.priceCents/installmentsNum):0;
  const cadenceDays=course?Math.round((course.durationMonths*30)/installmentsNum):0;
  // Al elegir el curso, sugerimos una cuota por mes de duración: antes
  // siempre arrancaba en 6 sin importar si el curso duraba 2 o 12 meses.
  function selectCourse(id:string){setCourseId(id);const selected=state.courses.find(c=>c.id===id);setInstallments(selected?String(Math.min(12,selected.durationMonths)):"")}
  function toggleWeekday(day:string){setWeekdays(current=>current.includes(day)?current.filter(d=>d!==day):[...current,day])}
  function close(){setCourseId(defaultCourseId??"");setInstallments("");setWeekdays([]);setCommissionPercent("40");onClose()}
  function submit(e:React.FormEvent<HTMLFormElement>){
    e.preventDefault();
    if(!course||weekdays.length===0)return;
    const data=new FormData(e.currentTarget);
    const time=String(data.get("time"));
    const orderedWeekdays=scheduleWeekdays.filter(d=>weekdays.includes(d));
    const cohort=addCohort({workspaceId,academyId,branchId:String(data.get("branchId")),name:String(data.get("name")),course:course.name,instructor:String(data.get("instructor")),schedule:`${orderedWeekdays.join(" y ")} · ${time}`,capacity:Math.max(1,Math.round(Number(data.get("capacity")))),installmentCents:perInstallment,installments:installmentsNum,durationMonths:course.durationMonths,commissionBps:Math.round(Math.max(0,Math.min(100,Number(commissionPercent)))*100),debtPolicy:"allow_with_warning",status:"scheduled"});
    // La comisión sola no dictaba clases: había que cargarlas una por una
    // a mano. Acá se generan todas de una, según los días elegidos.
    addClassesForCohort({cohortId:cohort.id,workspaceId,weekdays:orderedWeekdays,startsAt:time,durationMonths:course.durationMonths});
    close();
  }
  return <Modal open={open} onClose={close} title={defaultInstructor||defaultCourseId?"Nueva comisión":"Nuevo profesor / comisión"} description="Completá los datos en orden: quién la dicta, con qué curso, cuándo se cursa y cómo se cobra.">
    <form onSubmit={submit} className="grid gap-6">
      <div className="grid sm:grid-cols-2 gap-4">
        <h4 className="sm:col-span-2 text-xs font-bold uppercase muted tracking-wide">Profesor y curso</h4>
        <label className="label sm:col-span-2">Profesor<input className="field" name="instructor" list="instructor-options" defaultValue={defaultInstructor} placeholder="Nombre y apellido" required/><datalist id="instructor-options">{instructorNames.map(n=><option key={n} value={n}/>)}</datalist></label>
        {defaultCourseId
          ?<label className="label sm:col-span-2">Curso<div className="field flex items-center"><strong>{course?.name}</strong></div></label>
          :<label className="label sm:col-span-2">Curso<select className="field" value={courseId} onChange={e=>selectCourse(e.target.value)} required><option value="">Elegí un curso…</option>{state.courses.map(c=><option key={c.id} value={c.id}>{c.name} · {formatMoney(c.priceCents)} · {c.duration}</option>)}</select></label>}
        <label className="label sm:col-span-2">Nombre de la comisión<input className="field" name="name" placeholder="Ej. Barbería Inicial F" required/><p className="text-xs muted mt-1">Un nombre para distinguirla de otras comisiones del mismo curso.</p></label>
      </div>
      <div className="grid sm:grid-cols-2 gap-4 pt-5 border-t border-[var(--line)]">
        <h4 className="sm:col-span-2 text-xs font-bold uppercase muted tracking-wide">Horario y cupo</h4>
        <div className="label sm:col-span-2">Días de cursada<div className="flex flex-wrap gap-2 mt-1">{scheduleWeekdays.map(d=><button type="button" key={d} onClick={()=>toggleWeekday(d)} className={`btn ${weekdays.includes(d)?"btn-primary":"btn-secondary"}`}>{d}</button>)}</div><p className="text-xs muted mt-1">Elegí uno o varios días (ej. lunes y martes); las clases se generan solas con ese patrón hasta el fin del curso.</p></div>
        <label className="label">Hora de inicio<input className="field" name="time" type="time" defaultValue="18:00" required/></label>
        <label className="label">Sede<select className="field" name="branchId"><option value="branch-centro">Sede Centro</option><option value="branch-norte">Sede Norte</option><option value="branch-imperio">Sede Imperio</option></select></label>
        <label className="label sm:col-span-2">Cupo máximo<input className="field" name="capacity" type="number" min="1" defaultValue="10" required/></label>
      </div>
      <div className="grid sm:grid-cols-2 gap-4 pt-5 border-t border-[var(--line)]">
        <h4 className="sm:col-span-2 text-xs font-bold uppercase muted tracking-wide">Plan de pago y comisión</h4>
        <label className="label">Cantidad de cuotas<input className="field" name="installmentsCount" type="number" min="1" max="12" value={installments} onChange={e=>setInstallments(e.target.value)} required/><p className="text-xs muted mt-1">Sugerida según la duración del curso; se puede ajustar.</p></label>
        <label className="label">Comisión docente (%)<input className="field" name="commissionPercent" type="number" min="0" max="100" step="1" value={commissionPercent} onChange={e=>setCommissionPercent(e.target.value)} required/><p className="text-xs muted mt-1">Porcentaje de lo cobrado que se liquida al profesor.</p></label>
        {course&&<p className="sm:col-span-2 rounded-xl bg-sky-50 p-3 text-xs text-sky-900">Precio total <strong>{formatMoney(course.priceCents)}</strong> en <strong>{installmentsNum}</strong> cuotas de <strong>{formatMoney(perInstallment)}</strong>, una cada <strong>{cadenceDays}</strong> días.</p>}
      </div>
      <div className="flex justify-end gap-2"><button type="button" className="btn btn-secondary" onClick={close}>Cancelar</button><button className="btn btn-primary" disabled={!course||weekdays.length===0}>Crear comisión</button></div>
    </form>
  </Modal>;
}

function Teachers(){const{state}=useDemo();const[open,setOpen]=useState(false);const cohorts=state.cohorts.filter(c=>c.workspaceId===workspaceId);const names=Array.from(new Set(cohorts.map(c=>c.instructor)));return <><PageHeader eyebrow="Cuerpo docente" title="Profesores" description="Cada profesor agrupa sus comisiones, alumnos y liquidaciones en un solo lugar." action={<button onClick={()=>setOpen(true)} className="btn btn-primary"><Plus size={18}/> Nuevo profesor</button>}/><div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">{names.map(name=>{const mine=cohorts.filter(c=>c.instructor===name);const enrolled=mine.reduce((s,c)=>s+c.enrolled,0);const capacity=mine.reduce((s,c)=>s+c.capacity,0);const courses=Array.from(new Set(mine.map(c=>c.course)));return <Link key={name} href={`/app/teachers/${teacherSlug(name)}`} className="card p-5 hover:-translate-y-0.5 transition"><div className="flex items-center gap-3"><span className="grid place-items-center size-11 shrink-0 rounded-xl bg-[var(--brand-soft)] text-[var(--brand)] font-black text-xs">{name.split(" ").map(n=>n[0]).slice(0,2).join("")}</span><div className="min-w-0"><h3 className="font-black truncate">{name}</h3><p className="muted text-xs mt-0.5 truncate">{courses.join(" · ")}</p></div></div><div className="mt-5 grid grid-cols-2 gap-3 text-sm"><span><small className="block muted">Comisiones</small><strong>{mine.length}</strong></span><span><small className="block muted">Alumnos</small><strong>{enrolled} de {capacity}</strong></span></div><div className="mt-4 flex items-center gap-1 text-xs font-bold text-[var(--brand)]">Ver detalle <ChevronRight size={14}/></div></Link>})}</div><NewCohortModal open={open} onClose={()=>setOpen(false)}/></>}

function TeacherDetail({id}:{id:string}){const{state}=useDemo();const[open,setOpen]=useState(false);const[enrollCohort,setEnrollCohort]=useState<Cohort|null>(null);const all=state.cohorts.filter(c=>c.workspaceId===workspaceId);const name=all.map(c=>c.instructor).find(n=>teacherSlug(n)===id);if(!name)return <Empty title="Profesor no encontrado" detail="No existe o no dicta comisiones en este workspace."/>;const mine=all.filter(c=>c.instructor===name);const enrolled=mine.reduce((s,c)=>s+c.enrolled,0);const capacity=mine.reduce((s,c)=>s+c.capacity,0);return <><Link href="/app/teachers" className="text-sm font-bold text-[var(--brand)]">← Volver a profesores</Link><div className="flex flex-col sm:flex-row sm:items-center gap-4 mt-5 mb-6"><span className="grid place-items-center size-20 shrink-0 rounded-3xl bg-[var(--brand-soft)] text-[var(--brand)] text-2xl font-black">{name.split(" ").map(n=>n[0]).slice(0,2).join("")}</span><div><h2 className="text-3xl font-black">{name}</h2><p className="muted text-sm">{mine.length} comisiones activas · {enrolled} alumnos en nómina</p></div><div className="sm:ml-auto flex gap-2 flex-wrap"><button onClick={()=>setOpen(true)} className="btn btn-primary"><Plus size={17}/> Nueva comisión</button><Link href="/app/settlements" className="btn btn-secondary"><Landmark size={17}/> Liquidaciones</Link></div></div><div className="grid sm:grid-cols-3 gap-4 mb-5"><Metric label="Comisiones" value={String(mine.length)} note="Todas las sedes"/><Metric label="Alumnos en nómina" value={String(enrolled)} note={`${capacity-enrolled} vacantes totales`} tone="blue"/><Metric label="Ocupación" value={`${capacity?Math.round(enrolled/capacity*100):0}%`} note="Promedio de sus comisiones" tone="gold"/></div><div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">{mine.map(c=><div key={c.id} className="card p-5 hover:-translate-y-0.5 transition"><Link href={`/app/cohorts/${c.id}`} className="block"><div className="flex justify-between"><span className="badge">{c.code}</span><StatusBadge value={c.status}/></div><h3 className="text-lg font-black mt-5">{c.name}</h3><p className="muted text-sm mt-1">{c.course}</p><div className="mt-5 grid grid-cols-2 gap-3 text-sm"><span><small className="block muted">Horario</small><strong>{c.schedule}</strong></span><span><small className="block muted">Ocupación</small><strong>{c.enrolled} de {c.capacity}</strong></span></div></Link>{c.enrolled<c.capacity&&<button onClick={()=>setEnrollCohort(c)} className="btn btn-secondary w-full mt-4 text-xs">Inscribir alumno</button>}</div>)}</div><NewCohortModal open={open} onClose={()=>setOpen(false)} defaultInstructor={name}/>{enrollCohort&&<NewEnrollmentModal open onClose={()=>setEnrollCohort(null)} defaultCohortId={enrollCohort.id}/>}</>}

// Renderiza el destino final de inmediato (sin flash en blanco) mientras
// actualiza la URL en segundo plano, para rutas que cambiaron de lugar.
function CleanRedirect({to,children}:{to:string;children:React.ReactNode}){const router=useRouter();useEffect(()=>{router.replace(to)},[router,to]);return <>{children}</>;}

function Cohorts({ instructor=false }: { instructor?:boolean }) { const {state}=useDemo();const list=state.cohorts.filter(c=>c.workspaceId===workspaceId && (!instructor||c.instructor==="Tomás Herrera"));return <><PageHeader eyebrow="Oferta activa" title={instructor?"Mis comisiones":"Comisiones"} description={instructor?"Solo se muestran las comisiones donde sos profesor asignado.":"Ediciones concretas, cupos, horarios y reglas económicas."} action={!instructor&&<button className="btn btn-primary"><Plus size={18}/> Nueva comisión</button>}/><div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">{list.map(c=><Link key={c.id} href={`${instructor?"/instructor":"/app"}/cohorts/${c.id}`} className="card p-5 hover:-translate-y-0.5 transition"><div className="flex justify-between"><span className="badge">{c.code}</span><StatusBadge value={c.status}/></div><h3 className="text-lg font-black mt-5">{c.name}</h3><p className="muted text-sm mt-1">{c.course}</p><div className="mt-5 grid grid-cols-2 gap-3 text-sm"><span><small className="block muted">Profesor</small><strong>{c.instructor}</strong></span><span><small className="block muted">Horario</small><strong>{c.schedule}</strong></span><span><small className="block muted">Ocupación</small><strong>{c.enrolled} de {c.capacity}</strong></span><span><small className="block muted">Cuota</small><strong>{formatMoney(c.installmentCents)}</strong></span></div><div className="mt-5 h-2 rounded-full bg-gray-100 overflow-hidden"><div className={`h-full ${c.enrolled>=c.capacity?"bg-amber-500":"bg-[var(--brand)]"}`} style={{width:`${Math.min(100,c.enrolled/c.capacity*100)}%`}}/></div></Link>)}</div></> }

function Courses(){
  const{state,addCourse}=useDemo();const[open,setOpen]=useState(false);
  const list=state.courses.filter(c=>c.workspaceId===workspaceId);
  function submit(e:React.FormEvent<HTMLFormElement>){e.preventDefault();const data=new FormData(e.currentTarget);const months=Math.max(1,Math.round(Number(data.get("durationMonths"))));addCourse({workspaceId,name:String(data.get("name")),duration:`${months} ${months===1?"mes":"meses"}`,durationMonths:months,priceCents:Math.round(Number(data.get("price"))*100)});setOpen(false)}
  return <><PageHeader eyebrow="Catálogo" title="Cursos" description="Tocá un curso para ver sus comisiones y agregar una nueva." action={<button onClick={()=>setOpen(true)} className="btn btn-primary"><Plus size={18}/> Nuevo curso</button>}/><div className="grid md:grid-cols-3 gap-4">{list.map(c=>{const cohortCount=state.cohorts.filter(x=>x.workspaceId===workspaceId&&x.course===c.name).length;return <Link href={`/app/courses/${c.id}`} className="card p-5 hover:-translate-y-0.5 transition" key={c.id}><div className="flex items-start justify-between"><span className="grid place-items-center size-11 rounded-xl bg-[var(--brand-soft)] text-[var(--brand)]"><BookOpen/></span>{cohortCount>0&&<span className="badge badge-success">{cohortCount} comisiones</span>}</div><h3 className="font-black mt-4">{c.name}</h3><p className="muted text-sm mt-1">Código {c.code}</p><div className="flex justify-between border-t border-[var(--line)] mt-5 pt-4 text-sm"><span>{c.duration}</span><strong>{formatMoney(c.priceCents)}</strong></div></Link>})}</div><Modal open={open} onClose={()=>setOpen(false)} title="Nuevo curso" description="El código se genera automáticamente a partir del nombre; luego se crean comisiones concretas a partir de este curso, entrando al curso."><form onSubmit={submit} className="grid sm:grid-cols-2 gap-4"><label className="label sm:col-span-2">Nombre<input className="field" name="name" required/></label><label className="label">Duración (meses)<input className="field" name="durationMonths" type="number" min="1" max="24" defaultValue="3" required/></label><label className="label">Precio ARS<input className="field" name="price" type="number" min="1" required/></label><div className="sm:col-span-2 flex justify-end gap-2 mt-2"><button type="button" className="btn btn-secondary" onClick={()=>setOpen(false)}>Cancelar</button><button className="btn btn-primary">Crear curso</button></div></form></Modal></>
}

function CourseDetail({id}:{id:string}){
  const{state}=useDemo();
  const[open,setOpen]=useState(false);
  const course=state.courses.find(c=>c.id===id&&c.workspaceId===workspaceId);
  if(!course)return <Empty title="Curso no encontrado" detail="No existe o pertenece a otro workspace."/>;
  const cohorts=state.cohorts.filter(c=>c.workspaceId===workspaceId&&c.course===course.name);
  const totalEnrolled=cohorts.reduce((s,c)=>s+c.enrolled,0);
  const totalCapacity=cohorts.reduce((s,c)=>s+c.capacity,0);
  return <><Link href="/app/courses" className="text-sm font-bold text-[var(--brand)]">← Volver a cursos</Link>
    <PageHeader eyebrow={`Código ${course.code}`} title={course.name} description={`${course.duration} · ${formatMoney(course.priceCents)} · comisiones concretas de este curso`} action={<button onClick={()=>setOpen(true)} className="btn btn-primary"><Plus size={17}/> Nueva comisión</button>}/>
    <div className="grid sm:grid-cols-3 gap-4 mb-5"><Metric label="Comisiones" value={String(cohorts.length)} note="Todas las sedes"/><Metric label="Alumnos en nómina" value={String(totalEnrolled)} note={`${totalCapacity-totalEnrolled} vacantes totales`} tone="blue"/><Metric label="Ocupación" value={`${totalCapacity?Math.round(totalEnrolled/totalCapacity*100):0}%`} note="Promedio de sus comisiones" tone="gold"/></div>
    <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">{cohorts.map(c=><Link key={c.id} href={`/app/cohorts/${c.id}`} className="card p-5 hover:-translate-y-0.5 transition"><div className="flex justify-between"><span className="badge">{c.code}</span><StatusBadge value={c.status}/></div><h3 className="text-lg font-black mt-5">{c.name}</h3><p className="muted text-sm mt-1">{c.instructor}</p><div className="mt-5 grid grid-cols-2 gap-3 text-sm"><span><small className="block muted">Horario</small><strong>{c.schedule}</strong></span><span><small className="block muted">Ocupación</small><strong>{c.enrolled} de {c.capacity}</strong></span></div></Link>)}{cohorts.length===0&&<Empty title="Sin comisiones todavía" detail="Creá la primera comisión de este curso con el botón de arriba."/>}</div>
    <NewCohortModal open={open} onClose={()=>setOpen(false)} defaultCourseId={course.id}/>
  </>;
}

function AttendanceBody({classId,readOnly=false}:{classId:string;readOnly?:boolean}){
  const{state,setAttendance,closeAttendance}=useDemo();
  const[confirmClose,setConfirmClose]=useState(false);
  const activeClass=state.classes.find(c=>c.id===classId);
  if(!activeClass)return <Empty title="Clase no encontrada" detail="La clase ya no existe."/>;
  const cohort=state.cohorts.find(c=>c.id===activeClass.cohortId);
  const roster=state.enrollments.filter(e=>e.cohortId===activeClass.cohortId&&e.status!=="dropped_out").map(e=>state.students.find(s=>s.id===e.studentId)).filter((s):s is NonNullable<typeof s>=>Boolean(s));
  const attendanceOptions=[["present","Presente"],["late","Tarde"],["absent","Ausente"]] as const;
  const statusFor=(studentId:string)=>state.attendance.find(a=>a.classId===activeClass.id&&a.studentId===studentId)?.status;
  const closed=activeClass.attendanceClosed;
  const editable=!readOnly&&!closed;
  const presentCount=roster.filter(s=>statusFor(s.id)==="present").length;
  const absentCount=roster.filter(s=>statusFor(s.id)==="absent").length;
  const unmarkedCount=roster.filter(s=>!statusFor(s.id)).length;
  // Cerrar con alumnos sin marcar los deja "Pendiente" para siempre (las
  // correcciones post-cierre exigen solicitud), así que pedimos confirmación
  // explícita en vez de cerrar directo.
  const handleClose=()=>{ if(unmarkedCount>0&&!confirmClose){setConfirmClose(true);return} closeAttendance(activeClass.id); };
  return <section>
    <div className="rounded-2xl bg-[var(--sidebar)] text-white p-5 flex flex-col sm:flex-row sm:items-center gap-4">
      <div><p className="text-xs text-white/60">{formatShortDate(`${activeClass.date}T12:00:00Z`)} · {activeClass.startsAt} — {activeClass.endsAt} · {cohort?.instructor}</p><h3 className="text-xl font-black mt-1">{cohort?.name}</h3><p className="text-sm text-white/65 mt-1">{roster.length} alumnos en nómina · {closed?"Cerrada":"Ventana abierta"}</p></div>
      <div className="sm:ml-auto flex gap-2"><span className="badge bg-white/10 text-white">{pluralize(presentCount,"presente")}</span><span className="badge bg-white/10 text-white">{pluralize(absentCount,"ausente")}</span></div>
    </div>
    <div className="divide-y divide-[var(--line)] max-h-[45vh] overflow-y-auto mt-2">{roster.map(student=>{const value=statusFor(student.id);return <div key={student.id} className="p-4 flex flex-col sm:flex-row sm:items-center gap-3">
      <div className="flex items-center gap-3 flex-1"><span className="grid place-items-center size-10 rounded-xl bg-[var(--brand-soft)] text-[var(--brand)] font-black text-xs">{student.firstName[0]}{student.lastName[0]}</span><span><strong>{student.lastName}, {student.firstName}</strong><small className="block muted">{student.publicCode}</small></span></div>
      {editable
        ? <div className="grid grid-cols-3 gap-1">{attendanceOptions.map(([v,label])=><button key={v} onClick={()=>{setAttendance(activeClass.id,student.id,v);setConfirmClose(false)}} className={`min-h-10 rounded-xl px-3 text-xs font-bold border ${value===v?v==="absent"?"bg-red-50 border-red-300 text-red-800":"bg-[var(--brand-soft)] border-blue-200 text-[var(--brand)]":"border-[var(--line)]"}`}>{label}</button>)}</div>
        : <StatusBadge value={value??"pending"}/>}
    </div>})}</div>
    {!readOnly&&<footer className="pt-4 mt-2 border-t border-[var(--line)] grid gap-2"><div className="flex items-center justify-between"><p className="text-xs muted">{closed?"Asistencia cerrada. Las correcciones requieren solicitud.":`Cambios guardados en este dispositivo demo.${unmarkedCount>0?` ${pluralize(unmarkedCount,"alumno sin marcar","alumnos sin marcar")}.`:""}`}</p><button disabled={closed} onClick={handleClose} className={`btn ${confirmClose?"btn-danger":"btn-primary"}`}><Check size={17}/>{closed?"Cerrada":confirmClose?"Confirmar cierre igual":"Cerrar asistencia"}</button></div>{confirmClose&&!closed&&<p className="text-xs text-amber-700">Quedan {pluralize(unmarkedCount,"alumno","alumnos")} sin marcar: al cerrar quedan como pendientes y ya no se pueden editar sin una solicitud. Tocá de nuevo para confirmar.</p>}</footer>}
  </section>;
}

function Classes({instructor=false,readOnly=false}:{instructor?:boolean;readOnly?:boolean}){
  const{state,addClass}=useDemo();const[open,setOpen]=useState(false);const[attendanceClassId,setAttendanceClassId]=useState<string|null>(null);const[cohortFilter,setCohortFilter]=useState("all");
  const cohortOptions=state.cohorts.filter(c=>c.workspaceId===workspaceId&&(!instructor||c.instructor==="Tomás Herrera"));
  const allClasses=state.classes.filter(c=>c.workspaceId===workspaceId&&(!instructor||state.cohorts.find(x=>x.id===c.cohortId)?.instructor==="Tomás Herrera")).slice().sort((a,b)=>a.date.localeCompare(b.date)||a.startsAt.localeCompare(b.startsAt));
  const classes=cohortFilter==="all"?allClasses:allClasses.filter(c=>c.cohortId===cohortFilter);
  const attendanceClass=classes.find(c=>c.id===attendanceClassId);
  function submit(e:React.FormEvent<HTMLFormElement>){e.preventDefault();const data=new FormData(e.currentTarget);addClass({workspaceId,cohortId:String(data.get("cohortId")),date:String(data.get("date")),startsAt:String(data.get("startsAt")),endsAt:String(data.get("endsAt")),status:"scheduled"});setOpen(false)}
  return <><PageHeader eyebrow="Calendario" title="Clases" description="Tocá una clase para ver o tomar su asistencia." action={!instructor&&<button onClick={()=>setOpen(true)} className="btn btn-primary"><Plus size={18}/> Clase adicional</button>}/><label className="label max-w-sm mb-4">Filtrar por comisión<select className="field" value={cohortFilter} onChange={e=>setCohortFilter(e.target.value)}><option value="all">Todas las comisiones</option>{cohortOptions.map(c=><option key={c.id} value={c.id}>{c.name} · {c.code}</option>)}</select></label><section className="card table-wrap"><table><thead><tr><th>Fecha</th><th>Horario</th><th>Comisión</th><th>Profesor</th><th>Asistencia</th><th>Estado</th><th></th></tr></thead><tbody>{classes.map(c=>{const cohort=state.cohorts.find(x=>x.id===c.cohortId)!;return <tr key={c.id} onClick={()=>setAttendanceClassId(c.id)} className="cursor-pointer hover:bg-slate-50"><td><strong>{formatShortDate(`${c.date}T12:00:00Z`)}</strong></td><td>{c.startsAt} — {c.endsAt}</td><td>{cohort.name}<small className="block muted">{cohort.code}</small></td><td>{cohort.instructor}</td><td><StatusBadge value={c.attendanceClosed?"closed":"open"}/></td><td><StatusBadge value={c.status}/></td><td><ChevronRight size={18} className="muted"/></td></tr>})}{classes.length===0&&<tr><td colSpan={7}><Empty title="Sin clases" detail="No hay clases para este filtro todavía."/></td></tr>}</tbody></table></section>{!instructor&&<Modal open={open} onClose={()=>setOpen(false)} title="Clase adicional" description="Agrega una sesión fuera del patrón semanal para una comisión existente."><form onSubmit={submit} className="grid sm:grid-cols-2 gap-4"><label className="label sm:col-span-2">Comisión<select className="field" name="cohortId" required>{cohortOptions.map(c=><option key={c.id} value={c.id}>{c.name} · {c.code}</option>)}</select></label><label className="label sm:col-span-2">Fecha<input className="field" name="date" type="date" required/></label><label className="label">Inicio<input className="field" name="startsAt" type="time" required/></label><label className="label">Fin<input className="field" name="endsAt" type="time" required/></label><div className="sm:col-span-2 flex justify-end gap-2 mt-2"><button type="button" className="btn btn-secondary" onClick={()=>setOpen(false)}>Cancelar</button><button className="btn btn-primary">Agregar clase</button></div></form></Modal>}<Modal open={Boolean(attendanceClass)} onClose={()=>setAttendanceClassId(null)} title="Asistencia" description={readOnly?"Registro de solo lectura: la carga y el cierre los hace recepción o el profesor a cargo de la clase.":"La lista se deriva únicamente de inscripciones elegibles y se bloquea al cerrar."}>{attendanceClass&&<AttendanceBody classId={attendanceClass.id} readOnly={readOnly}/>}</Modal></>}

function StudentPicker({students,selectedId,onSelect}:{students:Student[];selectedId:string;onSelect(id:string):void}){
  const[query,setQuery]=useState("");
  const selected=students.find(s=>s.id===selectedId);
  const results=!selected&&query.trim().length>0?students.filter(s=>normalizeSearch(`${s.firstName} ${s.lastName} ${s.publicCode} ${s.dni}`).includes(normalizeSearch(query))).slice(0,8):[];
  if(selected)return <div className="field flex items-center justify-between"><span><strong>{selected.lastName}, {selected.firstName}</strong> <span className="muted">· {selected.publicCode}</span></span><button type="button" onClick={()=>{onSelect("");setQuery("")}} className="text-xs font-bold text-[var(--brand)]">Cambiar</button></div>;
  return <div className="relative"><input className="field" placeholder="Buscar por nombre, código o DNI…" value={query} onChange={e=>setQuery(e.target.value)} autoComplete="off"/>{results.length>0&&<div className="absolute z-10 mt-1 w-full card p-1 max-h-56 overflow-y-auto">{results.map(s=><button type="button" key={s.id} onClick={()=>{onSelect(s.id);setQuery("")}} className="block w-full text-left px-3 py-2 rounded-lg text-sm hover:bg-[var(--brand-soft)]">{s.lastName}, {s.firstName} <span className="muted text-xs">· {s.publicCode}</span></button>)}</div>}</div>;
}

function NewEnrollmentModal({open,onClose,defaultStudentId,defaultCohortId}:{open:boolean;onClose():void;defaultStudentId?:string;defaultCohortId?:string}){
  const{state,addEnrollment}=useDemo();
  const students=state.students.filter(s=>s.workspaceId===workspaceId&&s.status==="active");
  const cohorts=state.cohorts.filter(c=>c.workspaceId===workspaceId&&c.enrolled<c.capacity);
  const lockedCohort=defaultCohortId?state.cohorts.find(c=>c.id===defaultCohortId):undefined;
  const[studentId,setStudentId]=useState(defaultStudentId??"");
  const[courseId,setCourseId]=useState(()=>state.courses.find(co=>co.name===lockedCohort?.course)?.id??"");
  const[cohortId,setCohortId]=useState(defaultCohortId??"");
  const selectedCourse=state.courses.find(co=>co.id===courseId);
  const availableCohorts=cohorts.filter(c=>!selectedCourse||c.course===selectedCourse.name);
  const cohort=cohorts.find(c=>c.id===cohortId);
  // Sin este chequeo se podía inscribir al mismo alumno dos veces en la
  // misma comisión: la nómina lo listaba duplicado (mismo id de alumno)
  // y React tiraba warning de keys repetidas.
  const alreadyEnrolled=Boolean(studentId&&cohort&&state.enrollments.some(e=>e.studentId===studentId&&e.cohortId===cohort.id&&!["dropped_out","cancelled"].includes(e.status)));
  function close(){setStudentId("");setCourseId("");setCohortId("");onClose()}
  function submit(e:React.FormEvent<HTMLFormElement>){e.preventDefault();if(!cohort||!studentId||alreadyEnrolled)return;const price=state.courses.find(co=>co.name===cohort.course)?.priceCents??cohort.installmentCents*cohort.installments;addEnrollment({workspaceId,studentId,cohortId:cohort.id,status:"confirmed",agreedPriceCents:price,installments:cohort.installments});close()}
  return <Modal open={open} onClose={close} title="Inscribir alumno" description="El precio y las cuotas los define la comisión elegida; acá solo se confirma quién se inscribe.">
    <form onSubmit={submit} className="grid gap-4">
      <label className="label">Alumno<StudentPicker students={students} selectedId={studentId} onSelect={setStudentId}/></label>
      {defaultCohortId
        ?<label className="label">Comisión<div className="field flex items-center justify-between"><span><strong>{lockedCohort?.name}</strong> <span className="muted">· {lockedCohort?.code}</span></span></div></label>
        :<>
          <label className="label">Curso<select className="field" value={courseId} onChange={e=>{setCourseId(e.target.value);setCohortId("")}} required><option value="">Elegí un curso…</option>{state.courses.map(co=><option key={co.id} value={co.id}>{co.name}</option>)}</select></label>
          <label className="label">Comisión<select className="field" value={cohortId} onChange={e=>setCohortId(e.target.value)} required disabled={!courseId}><option value="">{courseId?"Elegí una comisión…":"Elegí un curso primero"}</option>{availableCohorts.map(c=><option key={c.id} value={c.id}>{c.name} · {c.capacity-c.enrolled} vacantes</option>)}</select></label>
        </>}
      {cohort&&(()=>{const price=state.courses.find(co=>co.name===cohort.course)?.priceCents??cohort.installmentCents*cohort.installments;const perInstallment=Math.floor(price/cohort.installments);return <p className="rounded-xl bg-sky-50 p-3 text-xs text-sky-900">Precio total <strong>{formatMoney(price)}</strong> en <strong>{cohort.installments}</strong> cuotas de {formatMoney(perInstallment)}.</p>})()}
      {alreadyEnrolled&&<p className="rounded-xl bg-red-50 p-3 text-xs text-red-900">Este alumno ya tiene una inscripción activa en esta comisión.</p>}
      <div className="flex justify-end gap-2 mt-2"><button type="button" className="btn btn-secondary" onClick={close}>Cancelar</button><button className="btn btn-primary" disabled={!studentId||!cohort||alreadyEnrolled}>Inscribir</button></div>
    </form>
  </Modal>;
}

function CheckIn(){const{state,addCheckin}=useDemo();const[token,setToken]=useState("");const[result,setResult]=useState<{result:"authorized"|"warning"|"denied";reason:string;name?:string}|null>(null);function validate(){const student=state.students.find(s=>s.workspaceId===workspaceId&&s.qrCode.toUpperCase()===token.trim().toUpperCase());const enrollment=student?state.enrollments.find(e=>e.studentId===student.id&&["attending","confirmed","overdue"].includes(e.status)):undefined;const cohort=enrollment?state.cohorts.find(c=>c.id===enrollment.cohortId):undefined;const compatible=Boolean(cohort&&state.classes.some(c=>c.cohortId===cohort.id&&["open","scheduled"].includes(c.status)));const overdue=student?state.charges.some(c=>c.studentId===student.id&&c.status==="overdue"):false;const hasPayment=student?state.payments.some(p=>p.studentId===student.id&&p.status==="confirmed"):false;const evaluated=evaluateQr({validToken:Boolean(student),activeStudent:student?.status==="active",activeEnrollment:Boolean(enrollment),hasCompatibleClass:compatible,overdue,hasConfirmedPayment:hasPayment,policy:cohort?.debtPolicy??"allow_with_warning"});const view={...evaluated,name:student?`${student.firstName} ${student.lastName}`:undefined};setResult(view);addCheckin({workspaceId,studentId:student?.id,classId:compatible?state.classes.find(c=>c.cohortId===cohort?.id)?.id:undefined,...evaluated})}return <><PageHeader eyebrow="Recepción" title="Check-in QR" description="Validación por credencial opaca, inscripción, clase, deuda y política de acceso."/><div className="grid xl:grid-cols-[.8fr_1.2fr] gap-5"><section className="card p-5 sm:p-7"><CameraScanner onCode={setToken}/><div className="flex items-center gap-3 my-5"><span className="h-px bg-[var(--line)] flex-1"/><span className="muted text-xs">o ingresar el código</span><span className="h-px bg-[var(--line)] flex-1"/></div><label className="label">Código QR manual<div className="flex gap-2"><input className="field uppercase" value={token} onChange={e=>setToken(e.target.value)} placeholder="Ej. ACA-0001-FUS"/><button className="btn btn-primary" onClick={validate} disabled={!token}>Validar</button></div></label><div className="flex flex-wrap gap-2 mt-4 text-xs"><button onClick={()=>setToken("ACA-0001-FUS")} className="badge">Probar verde</button><button onClick={()=>setToken("ACA-0005-FUS")} className="badge">Probar amarillo</button><button onClick={()=>setToken("ACA-0034-NOR")} className="badge">Probar rojo</button></div></section><section className="card p-5 sm:p-7 min-h-[450px] grid place-items-center">{!result?<div className="text-center max-w-sm"><QrCode size={55} className="mx-auto text-gray-300"/><h3 className="font-black mt-5">Esperando una credencial</h3><p className="muted text-sm mt-2">El resultado incluye texto e iconografía; nunca depende solamente del color.</p></div>:<div className={`w-full max-w-lg rounded-3xl p-7 text-center border-2 ${result.result==="authorized"?"bg-emerald-50 border-emerald-300 text-emerald-950":result.result==="warning"?"bg-amber-50 border-amber-300 text-amber-950":"bg-red-50 border-red-300 text-red-950"}`}>{result.result==="authorized"?<BadgeCheck size={58} className="mx-auto"/>:result.result==="warning"?<ShieldAlert size={58} className="mx-auto"/>:<AlertOctagon size={58} className="mx-auto"/>}<p className="eyebrow mt-5">{result.result==="authorized"?"Acceso autorizado":result.result==="warning"?"Requiere atención":"Acceso denegado"}</p><h3 className="text-2xl font-black mt-2">{result.name??"Credencial no reconocida"}</h3><p className="mt-3">{result.reason}</p><p className="text-sm mt-4 opacity-70">{formatTime(new Date())} · Sede Centro</p>{result.result==="warning"&&<div className="flex gap-2 justify-center mt-6"><button className="btn btn-secondary">Rechazar</button><button className="btn btn-primary">Permitir con motivo</button></div>}<button className="block mx-auto mt-6 text-sm font-bold underline" onClick={()=>{setResult(null);setToken("")}}>Escanear otro</button></div>}</section></div><section className="card mt-5"><div className="p-5 border-b border-[var(--line)]"><h3 className="font-black">Actividad reciente</h3></div><div className="table-wrap"><table><thead><tr><th>Hora</th><th>Alumno</th><th>Resultado</th><th>Motivo</th></tr></thead><tbody>{state.checkins.filter(c=>c.workspaceId===workspaceId).slice(0,8).map(c=>{const s=state.students.find(x=>x.id===c.studentId);return <tr key={c.id}><td>{formatTime(c.createdAt)}</td><td>{s?`${s.lastName}, ${s.firstName}`:"No identificado"}</td><td><StatusBadge value={c.result}/></td><td>{c.reason}</td></tr>})}</tbody></table></div></section></>}

function RequestsTab(){const{state,updateRequest}=useDemo();return <><p className="muted text-sm max-w-xl mb-4">Excepciones sensibles con solicitante, motivo y resolución por otro actor.</p><div className="grid gap-4">{state.requests.filter(r=>r.workspaceId===workspaceId).map(r=><article className="card p-5 flex flex-col md:flex-row md:items-center gap-4" key={r.id}><span className="grid place-items-center size-11 rounded-xl bg-amber-50 text-amber-700"><Clock3/></span><div className="flex-1"><div className="flex gap-2 items-center"><strong>{r.type.replaceAll("_"," ")}</strong><StatusBadge value={r.status}/></div><p className="text-sm mt-2">{r.reason}</p><p className="muted text-xs mt-2">Solicitó {r.requester} · {formatDateTime(r.createdAt)}</p></div>{r.status==="pending"&&<div className="flex gap-2"><button onClick={()=>updateRequest(r.id,"rejected")} className="btn btn-secondary"><X size={16}/> Rechazar</button><button onClick={()=>updateRequest(r.id,"approved")} className="btn btn-primary"><Check size={16}/> Aprobar</button></div>}</article>)}</div></>}

function AlertsTab(){const{state,updateAlert}=useDemo();return <><p className="muted text-sm max-w-xl mb-4">Señales automáticas priorizadas; resolver no elimina la evidencia.</p><div className="grid gap-4">{state.alerts.filter(a=>a.workspaceId===workspaceId).map(a=><article className="card p-5 flex gap-4" key={a.id}><span className={`grid place-items-center size-11 rounded-xl shrink-0 ${a.severity==="high"?"bg-red-50 text-red-700":a.severity==="medium"?"bg-amber-50 text-amber-700":"bg-sky-50 text-sky-700"}`}><ShieldAlert/></span><div className="flex-1"><div className="flex flex-wrap gap-2 items-center"><h3 className="font-black">{a.title}</h3><StatusBadge value={a.severity}/><StatusBadge value={a.status}/></div><p className="text-sm muted mt-2">{a.detail}</p><p className="text-xs muted mt-2">{formatDateTime(a.createdAt)}</p></div>{a.status!=="resolved"&&<button onClick={()=>updateAlert(a.id,"resolved")} className="btn btn-secondary">Resolver</button>}</article>)}</div></>}

function Bandeja({initialTab="solicitudes"}:{initialTab?:"solicitudes"|"alertas"}){
  const{state}=useDemo();
  const[tab,setTab]=useState<"solicitudes"|"alertas">(initialTab);
  const pending=state.requests.filter(r=>r.workspaceId===workspaceId&&r.status==="pending").length;
  const open=state.alerts.filter(a=>a.workspaceId===workspaceId&&a.status!=="resolved").length;
  const tabs=[["solicitudes",`Solicitudes${pending?` (${pending})`:""}`],["alertas",`Alertas${open?` (${open})`:""}`]] as const;
  return <>
    <PageHeader eyebrow="Bandeja de entrada" title="Bandeja" description="Solicitudes y alertas que requieren una decisión."/>
    <div className="flex gap-2 mb-5 border-b border-[var(--line)]">{tabs.map(([id,label])=><button key={id} onClick={()=>setTab(id)} className={`px-4 py-2.5 text-sm font-bold border-b-2 -mb-px transition-colors ${tab===id?"border-[var(--brand)] text-[var(--brand)]":"border-transparent muted hover:text-[#0b1220]"}`}>{label}</button>)}</div>
    {tab==="solicitudes"&&<RequestsTab/>}
    {tab==="alertas"&&<AlertsTab/>}
  </>;
}

function Settlements({instructor=false}:{instructor?:boolean}){
  const{state,closeSettlements}=useDemo();
  const allInstructors=Array.from(new Set(state.cohorts.filter(c=>c.workspaceId===workspaceId).map(c=>c.instructor)));
  const instructors=instructor?allInstructors.filter(n=>n==="Tomás Herrera"):allInstructors;
  const rows=instructors.map(name=>{
    const lastClosure=state.settlements.filter(s=>s.instructor===name).slice().sort((a,b)=>b.closedAt.localeCompare(a.closedAt))[0];
    const{baseCents,commissionCents}=settlementBase(state,name,lastClosure?.closedAt);
    const cohortCount=state.cohorts.filter(c=>c.workspaceId===workspaceId&&c.instructor===name).length;
    return{name,cohortCount,baseCents,commissionCents,lastClosure};
  });
  const history=state.settlements.filter(s=>!instructor||s.instructor==="Tomás Herrera").slice().sort((a,b)=>b.closedAt.localeCompare(a.closedAt));
  const totalBase=rows.reduce((s,r)=>s+r.baseCents,0);
  const totalCommission=rows.reduce((s,r)=>s+r.commissionCents,0);
  return <>
    <PageHeader eyebrow="Comisión docente" title={instructor?"Mis liquidaciones":"Liquidaciones"} description="Base comisionable por profesor: pagos confirmados de sus propias comisiones, según el porcentaje pactado en cada una." action={!instructor&&<button onClick={closeSettlements} className="btn btn-primary" disabled={totalBase===0}>Cerrar período</button>}/>
    <div className="grid sm:grid-cols-3 gap-4">
      <Metric label="Base abierta" value={formatMoney(totalBase)} note={pluralize(rows.filter(r=>r.baseCents>0).length,"profesor con actividad","profesores con actividad")}/>
      <Metric label="Comisión estimada" value={formatMoney(totalCommission)} note="Sujeta a cierre" tone="blue"/>
      <Metric label="Último cierre" value={history[0]?formatDate(history[0].closedAt):"Sin cierres"} note={history[0]?.periodLabel??"Todavía no se cerró ningún período"} tone="gold"/>
    </div>
    <section className="card mt-5 table-wrap"><table><thead><tr><th>Profesor</th><th>Comisiones</th><th>Base abierta</th><th>%</th><th>A liquidar</th><th>Desde</th></tr></thead><tbody>
      {rows.map(r=><tr key={r.name}><td><strong>{r.name}</strong></td><td>{r.cohortCount}</td><td>{formatMoney(r.baseCents)}</td><td>{r.baseCents?Math.round(r.commissionCents/r.baseCents*100):0}%</td><td><strong>{formatMoney(r.commissionCents)}</strong></td><td>{r.lastClosure?formatDate(r.lastClosure.closedAt):"Inicio"}</td></tr>)}
      {rows.length===0&&<tr><td colSpan={6}><Empty title="Sin profesores" detail="Todavía no hay comisiones dictadas en este workspace."/></td></tr>}
    </tbody></table></section>
    {history.length>0&&<section className="card mt-5 table-wrap"><div className="p-5 border-b border-[var(--line)]"><h3 className="font-black">Períodos cerrados</h3></div><table><thead><tr><th>Período</th><th>Profesor</th><th>Base</th><th>Comisión</th><th>Cerrado</th></tr></thead><tbody>{history.map(h=><tr key={h.id}><td>{h.periodLabel}</td><td>{h.instructor}</td><td>{formatMoney(h.baseCents)}</td><td><strong>{formatMoney(h.commissionCents)}</strong></td><td>{formatDate(h.closedAt)}</td></tr>)}</tbody></table></section>}
    <p className="text-xs muted mt-4">Un cierre congela un snapshot inmutable por profesor: solo incluye lo cobrado después de su último cierre.</p>
  </>;
}

async function downloadReport(format:"csv"|"xlsx"|"pdf",report="payments"){const response=await fetch(`/api/reports/export?format=${format}&report=${report}`);if(!response.ok)return;const blob=await response.blob();const url=URL.createObjectURL(blob);const a=document.createElement("a");a.href=url;a.download=`${report}-2026-07.${format}`;a.click();URL.revokeObjectURL(url)}
function ReportsTab(){const reports = [["Resumen mensual","26 secciones operativas y financieras","pdf"],["Pagos confirmados","Detalle, medio y asignación","xlsx"],["Alumnos activos","Legajo administrativo enmascarado","csv"],["Deuda y cargos","Saldos por vencimiento","xlsx"],["Auditoría","Acciones y correlación","csv"],["Liquidaciones","Base, exclusiones y pagos","pdf"]] as const;return <><p className="muted text-sm max-w-xl mb-4">Archivos filtrados por tenant, con descarga auditada y formatos interoperables.</p><div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">{reports.map(([title,desc,format])=><article className="card p-5" key={title}><span className="grid place-items-center size-11 rounded-xl bg-[var(--brand-soft)] text-[var(--brand)]"><FileSpreadsheet/></span><h3 className="font-black mt-4">{title}</h3><p className="muted text-sm mt-1">{desc}</p><div className="flex items-center justify-between border-t border-[var(--line)] pt-4 mt-5"><span className="badge">{format.toUpperCase()}</span><button onClick={()=>downloadReport(format,title.includes("Alumnos")?"students":title.includes("Auditoría")?"audit":"payments")} className="text-sm font-bold text-[var(--brand)] flex gap-2">Generar <ArrowDownToLine size={16}/></button></div></article>)}</div></>}

function ImportsTab(){const[file,setFile]=useState("");const[rows,setRows]=useState<string[][]>([]);const[error,setError]=useState("");async function load(e:React.ChangeEvent<HTMLInputElement>){const f=e.target.files?.[0];if(!f)return;setFile(f.name);setError("");const form=new FormData();form.set("file",f);const response=await fetch("/api/imports/preview",{method:"POST",body:form});const result=await response.json() as{error?:string;preview?:Array<{values:string[];errors:string[]}>};if(!response.ok){setError(result.error??"No se pudo procesar");return;}setRows((result.preview??[]).map(item=>[...item.values,item.errors.join("; ")||"Válida"]));}return <><div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 mb-4"><p className="muted text-sm max-w-xl">Plantilla, vista previa, errores por fila y confirmación explícita antes de escribir.</p><button className="btn btn-secondary"><Download size={17}/> Descargar plantilla</button></div><section className="card p-6"><label className="border-2 border-dashed border-blue-200 rounded-2xl min-h-52 grid place-items-center text-center p-8 cursor-pointer hover:bg-blue-50/40"><input type="file" accept=".csv,.xlsx" className="sr-only" onChange={load}/><span><Upload size={40} className="mx-auto text-[var(--brand)]"/><strong className="block mt-4">Seleccioná un archivo CSV o XLSX</strong><small className="muted block mt-2">Máximo 5 MB · alumnos, cursos, comisiones o inscripciones</small></span></label>{error&&<p className="rounded-xl bg-red-50 text-red-800 p-3 mt-4 text-sm">{error}</p>}{file&&rows.length>0&&<div className="mt-6"><div className="flex justify-between"><h3 className="font-black">Vista previa · {file}</h3><span className="badge badge-success">Validado</span></div><div className="table-wrap border border-[var(--line)] rounded-xl mt-4"><table><tbody>{rows.map((row,i)=><tr key={i}>{row.map((cell,j)=><td key={j}>{cell}</td>)}</tr>)}</tbody></table></div><div className="flex justify-end mt-4"><button className="btn btn-primary">Confirmar lote</button></div></div>}</section></>}

function Audit({global=false,compact=false}:{global?:boolean;compact?:boolean}){const{state}=useDemo();const items=state.audit.filter(a=>global||a.workspaceId===workspaceId);const header=compact?<div className="flex items-center justify-between mb-4"><p className="muted text-sm max-w-xl">Registro inmutable de actor, acción, entidad, origen y correlación.</p><button onClick={()=>downloadReport("csv","audit")} className="btn btn-secondary"><Download size={17}/> Exportar</button></div>:<PageHeader eyebrow="Evidencia append-only" title={global?"Auditoría global":"Auditoría"} description="Registro inmutable de actor, acción, entidad, origen y correlación." action={<button onClick={()=>downloadReport("csv","audit")} className="btn btn-secondary"><Download size={17}/> Exportar</button>}/>;return <>{header}<section className="card table-wrap"><table><thead><tr><th>Fecha</th><th>Actor</th><th>Acción</th><th>Entidad</th><th>Detalle</th></tr></thead><tbody>{items.map(a=><tr key={a.id}><td>{formatDateTime(a.createdAt)}</td><td><strong>{a.actor}</strong></td><td><code className="text-xs">{a.action}</code></td><td>{a.entity}</td><td>{a.detail}</td></tr>)}</tbody></table></section></>}

function Herramientas({initialTab="informes"}:{initialTab?:"informes"|"importaciones"|"auditoria"}){
  const user=useSessionUser();
  const isReceptionist=user.role==="receptionist";
  const[tab,setTab]=useState<"informes"|"importaciones"|"auditoria">(isReceptionist?"informes":initialTab);
  const tabs=(isReceptionist?[["informes","Informes"]]:[["informes","Informes"],["importaciones","Importaciones"],["auditoria","Auditoría"]]) as ReadonlyArray<readonly[typeof tab,string]>;
  return <>
    <PageHeader eyebrow="Administración" title="Herramientas" description="Exportaciones, carga de datos y registro de auditoría."/>
    {tabs.length>1&&<div className="flex gap-2 mb-5 border-b border-[var(--line)]">{tabs.map(([id,label])=><button key={id} onClick={()=>setTab(id)} className={`px-4 py-2.5 text-sm font-bold border-b-2 -mb-px transition-colors ${tab===id?"border-[var(--brand)] text-[var(--brand)]":"border-transparent muted hover:text-[#0b1220]"}`}>{label}</button>)}</div>}
    {tab==="informes"&&<ReportsTab/>}
    {tab==="importaciones"&&!isReceptionist&&<ImportsTab/>}
    {tab==="auditoria"&&!isReceptionist&&<Audit compact/>}
  </>;
}

